SELECT B1.* FROM ( SELECT A1.*, ROW_NUMBER() OVER () AS PAGEINDEX FROM ( SELECT REQ.REQUEST_NO AS requestNo, REQ.REQUEST_TYPE AS requestType, REQ.OBJECT_TYPE AS objectType, FN_GET_CD_NM('objectTypeWithP', REQ.OBJECT_TYPE, #{sessionLang}) AS objectTypeNm, REQ_MAPPING.BUSINESS_TYPE_CD AS businessTypeCd, FN_GET_CD_NM('businessTypeCd', REQ_MAPPING.BUSINESS_TYPE_CD, #{sessionLang}) AS businessTypeNm, REQ_MAPPING.DISTRIBUTE_TYPE_CD AS distributeTypeCd, FN_GET_CD_NM('distributeTypeCd', REQ_MAPPING.DISTRIBUTE_TYPE_CD, #{sessionLang}) AS distributeTypeNm, CASE WHEN request_deploy.DEPLOY_NORMAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.normalArea' AND lang.LANG_TYPE = #{sessionLang}) WHEN request_deploy.DEPLOY_SPECIAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.specialArea' AND lang.LANG_TYPE = #{sessionLang}) ELSE (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.viewing' AND lang.LANG_TYPE = #{sessionLang}) END AS deployTypeNm, CASE WHEN request_deploy.DEPLOY_NORMAL_YN = 'Y' THEN 'NORMAL' WHEN request_deploy.DEPLOY_SPECIAL_YN = 'Y' THEN 'SPECIAL' ELSE 'VIEWING' END AS deployType, REQ.REQUEST_PURPOSE AS requestPurpose, FN_GET_CD_NM('requestPurpose', REQ.REQUEST_PURPOSE, #{sessionLang}) AS requestPurposeNm, REQ_MAPPING.OBJECT_NO AS objectNo, REQ_MAPPING.REV_NO AS revNo, CASE REQ.OBJECT_TYPE WHEN 'DOC' THEN (SELECT MAX(REV_NO) FROM DOCS_DOCUMENT doc WHERE doc.DOCUMENT_NO = REQ_MAPPING.OBJECT_NO) WHEN 'DRAWING' THEN (SELECT MAX(REV_NO) FROM DOCS_DRAWING doc WHERE doc.DRAWING_NO = REQ_MAPPING.OBJECT_NO) WHEN 'SW' THEN (SELECT MAX(REV_NO) FROM DOCS_SW doc WHERE doc.SW_NO = REQ_MAPPING.OBJECT_NO) END AS lastRevNo, REQ_MAPPING.SW_VERSION_NO AS swVersionNo, REQ_MAPPING.DOC_VERSION_NO AS docVersionNo, REQ_MAPPING.OBJECT_NM AS objectNm, REQ_MAPPING.CURRENT_PAGE_NO AS currentPageNo, REQ_MAPPING.TOTAL_PAGE_NO AS totalPageNo, REQ_MAPPING.ECN_NO AS ecnNo, COALESCE(REQ_MAPPING.PRODUCT_CD, '') AS productNm, REQ_MAPPING.PRODUCT_CD AS productCd, REQ_MAPPING.BUSINESS_AREA_CD AS businessAreaCd, FN_GET_CD_NM('businessAreaCd', REQ_MAPPING.BUSINESS_AREA_CD, #{sessionLang}) AS businessAreaNm, REQ_MAPPING.PROTECT_YN AS protectYn, DEPLOY_COMPANY.COMPANY_CD AS deployCompanyCd, DEPLOY_COMPANY.COMPANY_NM AS deployCompanyNm, REQ_MAPPING.OBJECT_ID AS objectId, ACC_USER.USER_NM AS purchaserUserNm, CASE WHEN REQ.STATUS_CD = 'APPROVAL' THEN COALESCE(DEF_APPROVAL_USER.USER_CD, TL_APPROVAL_USER.USER_CD) WHEN REQ.STATUS_CD = 'REJECT' THEN REJECT_USER.USER_CD ELSE NULL END AS approvalUserCd, CASE WHEN REQ.STATUS_CD = 'APPROVAL' THEN COALESCE(DEF_APPROVAL_USER.USER_NM, TL_APPROVAL_USER.USER_NM) WHEN REQ.STATUS_CD = 'REJECT' THEN REJECT_USER.USER_NM ELSE NULL END AS approvalUserNm, REQ.APPROVAL_DT AS approvalDt, REQ.INSERT_DT AS requestDt, REQ_DETAIL.REQUEST_DESC AS requestReason, TO_CHAR(FILE_INFO.USE_END_YMD::DATE, 'YYYY-MM-DD') AS useEndYmd, REQ.STATUS_CD AS statusCd, FN_GET_CD_NM('requestStatusCd', REQ.STATUS_CD, #{sessionLang}) AS statusNm, FILE_INFO.DESTROY_STATUS_CD AS destroyStatusCd, FN_GET_CD_NM('destroyStatusCd', FILE_INFO.DESTROY_STATUS_CD, #{sessionLang}) AS destroyStatusNm, FN_GET_CD_NM('destroyType', FILE_INFO.DESTROY_TYPE, #{sessionLang}) AS destroyType, DEPLOY_USER.USER_NM AS companyUserNm, (SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = REQ.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT') AS deployUserNm, FILE_INFO.FILE_NO AS fileNo, FILE_INFO.ORG_FILE_NM AS orgFileNm, ACC_DETAIL.ACTUAL_USER_CD AS purchaserUserCd, (SELECT USER_NM FROM DOCS_USER t WHERE t.USER_CD = REQ.INSERT_USER_CD) AS requestUserNm, REQ.VENDOR_ACCEPT_YN AS vendorAcceptYn, FN_GET_CD_NM('vendorAcceptYn', REQ.VENDOR_ACCEPT_YN, 'ko') AS vendorAcceptNm FROM DOCS_REQUEST_FILE FILE_INFO INNER JOIN DOCS_REQUEST_MAPPING REQ_MAPPING ON FILE_INFO.REQUEST_NO = REQ_MAPPING.REQUEST_NO AND FILE_INFO.OBJECT_ID = REQ_MAPPING.OBJECT_ID INNER JOIN DOCS_REQUEST REQ ON REQ_MAPPING.REQUEST_NO = REQ.REQUEST_NO INNER JOIN DOCS_REQUEST_DETAIL REQ_DETAIL ON REQ_DETAIL.REQUEST_NO = REQ.REQUEST_NO AND REQ_DETAIL.APPROVAL_STATUS_CD = 'REQUEST' INNER JOIN DOCS_USER REQ_USER ON REQ_USER.USER_CD = REQ_DETAIL.ACTUAL_USER_CD INNER JOIN DOCS_REQUEST_DEPLOY REQUEST_DEPLOY ON REQUEST_DEPLOY.REQUEST_NO = REQ.REQUEST_NO INNER JOIN DOCS_USER DEPLOY_USER ON DEPLOY_USER.USER_CD = REQUEST_DEPLOY.DEPLOY_USER_CD INNER JOIN DOCS_COMPANY DEPLOY_COMPANY ON DEPLOY_COMPANY.COMPANY_CD = DEPLOY_USER.COMPANY_CD INNER JOIN DOCS_REQUEST_DETAIL ACC_DETAIL ON ACC_DETAIL.REQUEST_NO = REQ.REQUEST_NO AND ACC_DETAIL.APPROVAL_STATUS_CD = 'ACCEPT' INNER JOIN DOCS_USER ACC_USER ON ACC_USER.USER_CD = ACC_DETAIL.ORIGINAL_USER_CD LEFT JOIN DOCS_REQUEST_DETAIL TL_APPROVAL_DETAIL ON TL_APPROVAL_DETAIL.REQUEST_NO = REQ.REQUEST_NO AND TL_APPROVAL_DETAIL.APPROVAL_STATUS_CD = 'APPROVAL' AND TL_APPROVAL_DETAIL.APPROVAL_GRADE_CD = 'TL' LEFT JOIN DOCS_USER TL_APPROVAL_USER ON TL_APPROVAL_USER.USER_CD = TL_APPROVAL_DETAIL.ACTUAL_USER_CD LEFT JOIN DOCS_REQUEST_DETAIL DEF_APPROVAL_DETAIL ON DEF_APPROVAL_DETAIL.REQUEST_NO = REQ.REQUEST_NO AND DEF_APPROVAL_DETAIL.APPROVAL_STATUS_CD = 'APPROVAL' AND DEF_APPROVAL_DETAIL.APPROVAL_GRADE_CD = 'DEF' LEFT JOIN DOCS_USER DEF_APPROVAL_USER ON DEF_APPROVAL_USER.USER_CD = DEF_APPROVAL_DETAIL.ACTUAL_USER_CD LEFT JOIN DOCS_APPROVAL_FILE APPROVAL_FILE ON APPROVAL_FILE.REQUEST_NO = REQ.REQUEST_NO AND APPROVAL_FILE.OBJECT_ID = FILE_INFO.OBJECT_ID AND APPROVAL_FILE.FILE_NO = FILE_INFO.FILE_NO LEFT JOIN DOCS_REQUEST_DETAIL REJECT_DETAIL ON REJECT_DETAIL.REQUEST_NO = REQ.REQUEST_NO AND REJECT_DETAIL.ACTION_CD = 'REJECT' LEFT JOIN DOCS_USER REJECT_USER ON REJECT_USER.USER_CD = REJECT_DETAIL.ACTUAL_USER_CD WHERE REQ.REQUEST_TYPE='DISTRIBUTION'
ORDER BY ${sortColumn} ${order}
) A1 WHERE 1=1
AND requestNo = #{requestNo}
AND deployCompanyCd = #{deployCompanyCd}
AND objectNo LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND useEndYmd < TO_CHAR(CURRENT_DATE, 'YYYY-MM-DD')
AND businessAreaCd = #{businessAreaCd}
AND approvalUserCd = #{approvalUserCd}
AND purchaserUserCd = #{purchaserUserCd}
AND statusCd = #{statusCd}
AND statusCd IN ('APPROVAL', 'REJECT')
AND productCd = #{productCd}
AND objectType = #{objectType}
AND destroyStatusCd = #{destroyStatusCd}
AND distributeTypeCd = #{distributeTypeCd}
AND deployType = #{deployType}
AND (
(objectType = 'DRAWING' AND objectNo LIKE '%' || UPPER(TRIM(#{drawingInfo.drawingNo})) || '%')
OR
(objectType = 'DOC' AND objectNo LIKE '%' || UPPER(TRIM(#{documentInfo.documentNo})) || '%')
OR
(objectType = 'SW' AND objectNo LIKE '%' || UPPER(TRIM(#{swInfo.swNo})) || '%')
)
AND (
(objectType = 'DRAWING' AND objectNo = UPPER(TRIM(#{drawingInfo.drawingNo})))
OR
(objectType = 'DOC' AND objectNo = UPPER(TRIM(#{documentInfo.documentNo})))
OR
(objectType = 'SW' AND objectNo = UPPER(TRIM(#{swInfo.swNo})))
)
AND requestDt BETWEEN TO_DATE(#{requestStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{requestEndDt}, 'YYYY-MM-DD') + INTERVAL '1' DAY
) B1
WHERE PAGEINDEX >= #{start}

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT A1.* FROM ( SELECT REQ.REQUEST_NO AS requestNo, REQ.REQUEST_TYPE AS requestType, REQ.OBJECT_TYPE AS objectType, FN_GET_CD_NM('objectTypeWithP', REQ.OBJECT_TYPE, #{sessionLang}) AS objectTypeNm, REQ_MAPPING.BUSINESS_TYPE_CD AS businessTypeCd, FN_GET_CD_NM('businessTypeCd', REQ_MAPPING.BUSINESS_TYPE_CD, #{sessionLang}) AS businessTypeNm, REQ_MAPPING.DISTRIBUTE_TYPE_CD AS distributeTypeCd, FN_GET_CD_NM('distributeTypeCd', REQ_MAPPING.DISTRIBUTE_TYPE_CD, #{sessionLang}) AS distributeTypeNm, CASE WHEN request_deploy.DEPLOY_NORMAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.normalArea' AND lang.LANG_TYPE = #{sessionLang}) WHEN request_deploy.DEPLOY_SPECIAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.specialArea' AND lang.LANG_TYPE = #{sessionLang}) ELSE (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.viewing' AND lang.LANG_TYPE = #{sessionLang}) END AS deployTypeNm, CASE WHEN request_deploy.DEPLOY_NORMAL_YN = 'Y' THEN 'NORMAL' WHEN request_deploy.DEPLOY_SPECIAL_YN = 'Y' THEN 'SPECIAL' ELSE 'VIEWING' END AS deployType, REQ.REQUEST_PURPOSE AS requestPurpose, FN_GET_CD_NM('requestPurpose', REQ.REQUEST_PURPOSE, #{sessionLang}) AS requestPurposeNm, REQ_MAPPING.OBJECT_NO AS objectNo, REQ_MAPPING.REV_NO AS revNo, CASE REQ.OBJECT_TYPE WHEN 'DOC' THEN (SELECT MAX(REV_NO) FROM DOCS_DOCUMENT doc WHERE doc.DOCUMENT_NO = REQ_MAPPING.OBJECT_NO) WHEN 'DRAWING' THEN (SELECT MAX(REV_NO) FROM DOCS_DRAWING doc WHERE doc.DRAWING_NO = REQ_MAPPING.OBJECT_NO) WHEN 'SW' THEN (SELECT MAX(REV_NO) FROM DOCS_SW doc WHERE doc.SW_NO = REQ_MAPPING.OBJECT_NO) END AS lastRevNo, REQ_MAPPING.SW_VERSION_NO AS swVersionNo, REQ_MAPPING.DOC_VERSION_NO AS docVersionNo, REQ_MAPPING.OBJECT_NM AS objectNm, REQ_MAPPING.CURRENT_PAGE_NO AS currentPageNo, REQ_MAPPING.TOTAL_PAGE_NO AS totalPageNo, REQ_MAPPING.ECN_NO AS ecnNo, COALESCE(REQ_MAPPING.PRODUCT_CD, '') AS productNm, REQ_MAPPING.PRODUCT_CD AS productCd, REQ_MAPPING.BUSINESS_AREA_CD AS businessAreaCd, FN_GET_CD_NM('businessAreaCd', REQ_MAPPING.BUSINESS_AREA_CD, #{sessionLang}) AS businessAreaNm, REQ_MAPPING.PROTECT_YN AS protectYn, DEPLOY_COMPANY.COMPANY_CD AS deployCompanyCd, DEPLOY_COMPANY.COMPANY_NM AS deployCompanyNm, REQ_MAPPING.OBJECT_ID AS objectId, ACC_USER.USER_NM AS purchaserUserNm, CASE WHEN REQ.STATUS_CD = 'APPROVAL' THEN COALESCE(DEF_APPROVAL_USER.USER_CD, TL_APPROVAL_USER.USER_CD) WHEN REQ.STATUS_CD = 'REJECT' THEN REJECT_USER.USER_CD ELSE NULL END AS approvalUserCd, CASE WHEN REQ.STATUS_CD = 'APPROVAL' THEN COALESCE(DEF_APPROVAL_USER.USER_NM, TL_APPROVAL_USER.USER_NM) WHEN REQ.STATUS_CD = 'REJECT' THEN REJECT_USER.USER_NM ELSE NULL END AS approvalUserNm, REQ.APPROVAL_DT AS approvalDt, REQ.INSERT_DT AS requestDt, REQ_DETAIL.REQUEST_DESC AS requestReason, TO_CHAR(FILE_INFO.USE_END_YMD::DATE, 'YYYY-MM-DD') AS useEndYmd, REQ.STATUS_CD AS statusCd, FN_GET_CD_NM('requestStatusCd', REQ.STATUS_CD, #{sessionLang}) AS statusNm, FILE_INFO.DESTROY_STATUS_CD AS destroyStatusCd, FN_GET_CD_NM('destroyStatusCd', FILE_INFO.DESTROY_STATUS_CD, #{sessionLang}) AS destroyStatusNm, FN_GET_CD_NM('destroyType', FILE_INFO.DESTROY_TYPE, #{sessionLang}) AS destroyType, DEPLOY_USER.USER_NM AS companyUserNm, (SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = REQ.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT') AS deployUserNm, FILE_INFO.FILE_NO AS fileNo, FILE_INFO.ORG_FILE_NM AS orgFileNm, ACC_DETAIL.ACTUAL_USER_CD AS purchaserUserCd, (SELECT USER_NM FROM DOCS_USER t WHERE t.USER_CD = REQ.INSERT_USER_CD) AS requestUserNm FROM DOCS_REQUEST_FILE FILE_INFO INNER JOIN DOCS_REQUEST_MAPPING REQ_MAPPING ON FILE_INFO.REQUEST_NO = REQ_MAPPING.REQUEST_NO AND FILE_INFO.OBJECT_ID = REQ_MAPPING.OBJECT_ID INNER JOIN DOCS_REQUEST REQ ON REQ_MAPPING.REQUEST_NO = REQ.REQUEST_NO INNER JOIN DOCS_REQUEST_DETAIL REQ_DETAIL ON REQ_DETAIL.REQUEST_NO = REQ.REQUEST_NO AND REQ_DETAIL.APPROVAL_STATUS_CD = 'REQUEST' INNER JOIN DOCS_USER REQ_USER ON REQ_USER.USER_CD = REQ_DETAIL.ACTUAL_USER_CD INNER JOIN DOCS_REQUEST_DEPLOY REQUEST_DEPLOY ON REQUEST_DEPLOY.REQUEST_NO = REQ.REQUEST_NO INNER JOIN DOCS_USER DEPLOY_USER ON DEPLOY_USER.USER_CD = REQUEST_DEPLOY.DEPLOY_USER_CD INNER JOIN DOCS_COMPANY DEPLOY_COMPANY ON DEPLOY_COMPANY.COMPANY_CD = DEPLOY_USER.COMPANY_CD INNER JOIN DOCS_REQUEST_DETAIL ACC_DETAIL ON ACC_DETAIL.REQUEST_NO = REQ.REQUEST_NO AND ACC_DETAIL.APPROVAL_STATUS_CD = 'ACCEPT' INNER JOIN DOCS_USER ACC_USER ON ACC_USER.USER_CD = ACC_DETAIL.ORIGINAL_USER_CD LEFT JOIN DOCS_REQUEST_DETAIL TL_APPROVAL_DETAIL ON TL_APPROVAL_DETAIL.REQUEST_NO = REQ.REQUEST_NO AND TL_APPROVAL_DETAIL.APPROVAL_STATUS_CD = 'APPROVAL' AND TL_APPROVAL_DETAIL.APPROVAL_GRADE_CD = 'TL' LEFT JOIN DOCS_USER TL_APPROVAL_USER ON TL_APPROVAL_USER.USER_CD = TL_APPROVAL_DETAIL.ACTUAL_USER_CD LEFT JOIN DOCS_REQUEST_DETAIL DEF_APPROVAL_DETAIL ON DEF_APPROVAL_DETAIL.REQUEST_NO = REQ.REQUEST_NO AND DEF_APPROVAL_DETAIL.APPROVAL_STATUS_CD = 'APPROVAL' AND DEF_APPROVAL_DETAIL.APPROVAL_GRADE_CD = 'DEF' LEFT JOIN DOCS_USER DEF_APPROVAL_USER ON DEF_APPROVAL_USER.USER_CD = DEF_APPROVAL_DETAIL.ACTUAL_USER_CD LEFT JOIN DOCS_APPROVAL_FILE APPROVAL_FILE ON APPROVAL_FILE.REQUEST_NO = REQ.REQUEST_NO AND APPROVAL_FILE.OBJECT_ID = FILE_INFO.OBJECT_ID AND APPROVAL_FILE.FILE_NO = FILE_INFO.FILE_NO LEFT JOIN DOCS_REQUEST_DETAIL REJECT_DETAIL ON REJECT_DETAIL.REQUEST_NO = REQ.REQUEST_NO AND REJECT_DETAIL.ACTION_CD = 'REJECT' LEFT JOIN DOCS_USER REJECT_USER ON REJECT_USER.USER_CD = REJECT_DETAIL.ACTUAL_USER_CD WHERE REQ.REQUEST_TYPE='DISTRIBUTION' ) A1 WHERE 1=1
AND requestNo = #{requestNo}
AND deployCompanyCd = #{deployCompanyCd}
AND objectNo LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND useEndYmd < TO_CHAR(CURRENT_DATE, 'YYYY-MM-DD')
AND businessAreaCd = #{businessAreaCd}
AND approvalUserCd = #{approvalUserCd}
AND purchaserUserCd = #{purchaserUserCd}
AND statusCd = #{statusCd}
AND statusCd IN ('APPROVAL', 'REJECT')
AND productCd = #{productCd}
AND objectType = #{objectType}
AND destroyStatusCd = #{destroyStatusCd}
AND distributeTypeCd = #{distributeTypeCd}
AND deployType = #{deployType}
) B1

SELECT *
FROM DOCS_DRAWING
WHERE DRAWING_NO IN (

	#{DrawingInfoVO.drawingNo}

)

/* 업체 리스트 */ SELECT * FROM ( SELECT ROW_NUMBER() OVER (
ORDER BY companyNm ASC
ORDER BY ${sortColumn} ${order}
) AS PAGEINDEX, B1.* FROM ( SELECT BIZ_NO AS bizNo, COMPANY_NM AS companyNm, COMPANY_CD AS companyCd, CASE WHEN (USE_YN = 'N' OR DEL_YN = 'Y') THEN '거래중단' ELSE '' END AS stopDeal FROM DOCS_COMPANY WHERE 1 = 1
AND BIZ_NO LIKE '%' || #{bizNo} || '%'
AND COMPANY_NM LIKE '%' || #{companyNm} || '%'
) B1 ) A WHERE PAGEINDEX >= #{start}
AND PAGEINDEX <= #{end}

