UPDATE DOCS_COMPANY
SET DEL_YN = 'Y'
WHERE COMPANY_CD = #{companyCd}

UPDATE DOCS_USER
SET USE_YN = 'N'
WHERE COMPANY_CD = #{companyCd}

UPDATE DOCS_APPROVAL_FILE
SET LAST_DESTROY_REQUEST_NO = #{destroyRequestNo}
WHERE REQUEST_NO = #{requestNo}
  AND OBJECT_ID = #{objectId}

UPDATE ITN_VENDOR
SET VENDOR_STATUS = 'N', CN_CHANGE_TYPE = 'U'
WHERE VENDOR_CD = #{bizNo}

