UPDATE DOCS_APPROVAL_FILE
SET LAST_DESTROY_REQUEST_NO = (
	SELECT DESTROY_REQUEST_NO
	FROM DOCS_DESTROY_REQUEST_MAPPING
	WHERE REQUEST_NO = #{requestNo}
	  AND OBJECT_ID = #{objectId}
), DESTROY_STATUS_CD = '2'
WHERE REQUEST_NO = #{requestNo}
  AND OBJECT_ID = #{objectId}

UPDATE DOCS_REQUEST_FILE
SET DESTROY_TYPE = '4',
	DESTROY_STATUS_CD = '1'
WHERE REQUEST_NO = #{requestNo}
  AND OBJECT_ID = #{objectId}
  AND FILE_NO = CAST(#{fileNo} AS INTEGER)
